<script setup lang="ts">import type { BpmBusinessObjectDetail,BpmBusinessObjectReference } from '#/api/system/bpm';import { computed,onMounted,ref } from 'vue';import { useRoute,useRouter } from 'vue-router';import { useAccess } from '@vben/access';import { ArtDetailPage } from '@vben/art-hooks/detail';import { ElButton,ElDescriptions,ElDescriptionsItem,ElTag } from 'element-plus';import { exportBpmBusinessObjectTechnicalDetail,getBpmBusinessObjectDetail,queryBpmBusinessObjectReferences,upgradeBpmBusinessObjectV1 } from '#/api/system/bpm';import BpmTechnicalContractPanel from './components/bpm-technical-contract-panel.vue';import BpmVersionReferencePanel from './components/bpm-version-reference-panel.vue';const route=useRoute();const router=useRouter();const detail=ref<BpmBusinessObjectDetail>();const references=ref<BpmBusinessObjectReference[]>([]);const {hasAccessByCodes}=useAccess();const canTechnical=computed(()=>hasAccessByCodes(['bpm:business-contract:technical']));onMounted(async()=>{const key=String(route.query.contractKey),version=Number(route.query.contractVersion);detail.value=await getBpmBusinessObjectDetail(key,version);references.value=await queryBpmBusinessObjectReferences(key,version)});async function upgrade(){if(!detail.value)return;const draft=await upgradeBpmBusinessObjectV1(detail.value);void router.push({path:'/system/bpm/business-contract/editor',query:{contractKey:draft.contractKey,contractVersion:draft.contractVersion}})}async function exportProtocol(){if(!detail.value)return;const blob=await exportBpmBusinessObjectTechnicalDetail(detail.value.contractKey,detail.value.contractVersion) as Blob;const url=URL.createObjectURL(blob);const link=document.createElement('a');link.href=url;link.download=`${detail.value.contractKey}-v${detail.value.contractVersion}.json`;link.click();URL.revokeObjectURL(url)}</script>
<template><ArtDetailPage title="业务对象详情"><template #actions><ElButton @click="router.back()">返回</ElButton><ElButton v-if="detail?.schemaVersion===1" type="primary" @click="upgrade">升级为可视化草稿</ElButton><ElButton v-if="canTechnical" @click="exportProtocol">导出技术协议</ElButton></template><template v-if="detail"><ElDescriptions :column="2" border><ElDescriptionsItem label="业务对象名称">{{detail.objectName}}</ElDescriptionsItem><ElDescriptionsItem label="业务对象编码">{{detail.contractKey}}</ElDescriptionsItem><ElDescriptionsItem label="版本">v{{detail.contractVersion}}</ElDescriptionsItem><ElDescriptionsItem label="状态"><ElTag>{{detail.lifecycleState}}</ElTag></ElDescriptionsItem><ElDescriptionsItem :span="2" label="业务说明">{{detail.description||'暂无'}}</ElDescriptionsItem><ElDescriptionsItem :span="2" label="业务摘要">{{detail.businessSummary}}</ElDescriptionsItem></ElDescriptions><section><h3>Graph 引用</h3><BpmVersionReferencePanel :references="references"/></section><section v-if="canTechnical"><BpmTechnicalContractPanel :contract-key="detail.contractKey" :contract-version="detail.contractVersion"/></section></template></ArtDetailPage></template><style scoped>section{margin-top:16px}h3{font-size:16px;line-height:24px;margin:0 0 12px;font-weight:600;letter-spacing:0}@media(max-width:640px){:deep(.el-descriptions__body){overflow-x:auto}}</style>
